// Subject ID → report key mapping (handles variations)
const SUBJECT_MAP = {
  chemistry: 'chemistry',
  physics: 'physics',
  biology: 'biology',
  mathematics: 'mathematics',
  math: 'mathematics',
  maths: 'mathematics',
  economics: 'economics',
  english: 'english',
  business: 'business',
  business_studies: 'business',
  computer_science: 'computer_science',
  computing: 'computer_science',
  accounting: 'accounting',
  history: 'history',
  pakistan_studies: 'pakistan_studies',
  islamiyat: 'islamiyat',
  geography: 'geography',
  urdu: 'urdu',
  english_literature: 'english_literature',
  eng_literature: 'english_literature',
  eng_lit: 'english_literature',
  // A Level subjects use same reports
  chemistry_al: 'chemistry',
  physics_al: 'physics',
  biology_al: 'biology',
  mathematics_al: 'mathematics',
  economics_al: 'economics',
  business_al: 'business',
  cs_al: 'computer_science',
};

/**
 * Check a student's answer against common examiner-reported mistakes.
 * Returns an array of matching reports: { topic, mistake, examinerComment }
 */
function checkExaminerMistakes(studentAnswer, subject) {
  if (!studentAnswer || !subject) return [];

  const key = SUBJECT_MAP[subject.toLowerCase()] || subject.toLowerCase();
  const reports = EXAMINER_REPORTS[key];
  if (!reports) return [];

  const lower = studentAnswer.toLowerCase();
  const matches = [];

  for (const report of reports) {
    for (const trigger of report.triggers) {
      if (lower.includes(trigger.toLowerCase())) {
        matches.push({
          topic: report.topic,
          mistake: report.mistake,
          examinerComment: report.examinerComment,
        });
        break; // one match per report entry is enough
      }
    }
  }

  return matches;
}

/**
 * Returns a prompt injection string if examiner-reported mistakes are detected,
 * or empty string if none found.
 */
function getExaminerReportInjection(studentAnswer, subject) {
  const mistakes = checkExaminerMistakes(studentAnswer, subject);
  if (!mistakes.length) return '';

  const lines = mistakes.map(m =>
    `- Topic: ${m.topic}\n  Common mistake detected: "${m.mistake}"\n  Examiner report says: "${m.examinerComment}"`
  ).join('\n');

  return `\n\n[EXAMINER REPORT CHECK]\nThe student has made mistake(s) that Cambridge examiners specifically penalise:\n${lines}\nCorrect this explicitly before moving on. Quote what the examiner report says so the student understands this is a real mark-losing error.`;
}

/**
 * Get all examiner reports for a given subject.
 * Handles variations in subject naming (spaces, underscores, etc.)
 */
function getExaminerReportsBySubject(subject) {
  const s = subject?.toLowerCase().replace(/\s+/g, '_') || '';
  return EXAMINER_REPORTS[s] || EXAMINER_REPORTS[s.replace('_', '')] || [];
}

/**
 * Get common mistakes for a specific subject and topic.
 * Returns all entries whose topic includes the search term.
 */
function getCommonMistakes(subject, topic) {
  const reports = getExaminerReportsBySubject(subject);
  const t = (topic || '').toLowerCase();
  return reports.filter(r => r.topic.toLowerCase().includes(t));
}

/**
 * Get all entries that have a markSchemePhrase for a subject.
 * Useful for injecting exact examiner phrasing into teaching.
 */
function getCriticalPhrases(subject) {
  const reports = getExaminerReportsBySubject(subject);
  return reports.filter(r => r.markSchemePhrase).map(r => ({ topic: r.topic, phrase: r.markSchemePhrase }));
}

/**
 * Get the most frequently occurring mistakes for a subject.
 * Returns entries where frequency is 'always'.
 */
function getMostFrequentMistakes(subject) {
  const reports = getExaminerReportsBySubject(subject);
  return reports.filter(r => r.frequency === 'always');
}

/**
 * Get total count of all examiner report entries across all subjects.
 */
function getTotalEntryCount() {
  return Object.values(EXAMINER_REPORTS).reduce((sum, arr) => sum + arr.length, 0);
}

module.exports = {
  EXAMINER_REPORTS,
  checkExaminerMistakes,
  getExaminerReportInjection,
  getExaminerReportsBySubject,
  getCommonMistakes,
  getCriticalPhrases,
  getMostFrequentMistakes,
  getTotalEntryCount,
};
